#!/usr/bin/env python\n"""Evaluate the skin‑cancer model on the HAM10000 test set.\n\nThis script is a thin wrapper around :pymod:`tests.validation_suite` and is provided\nfor convenience when the user wants a simple entry‑point without importing the\nmodule manually.\n\nRunning the script will execute the full validation pipeline and output the\nfinal validation report generated by the suite.\n\nUsage:\n    python -m tests.evaluate_test_set\n\nThe script relies on the same configuration and paths defined in\n:pymod:`tests.validation_suite`.\n"""\n\nimport sys\nfrom pathlib import Path\n\n# Ensure the repository root is on the Python path so that imports work\nROOT = Path(__file__).resolve().parents[2]\nif str(ROOT) not in sys.path:\n    sys.path.insert(0, str(ROOT))\n\n# Import the main function from the validation suite\nfrom tests.validation_suite import main as run_validation\n\nif __name__ == "__main__":\n    print("Running full validation suite for the skin‑cancer model…")\n    run_validation()\n    print("Validation complete. See the `reports/` directory for detailed markdown reports.")\n
